<template>
    <transition name="back-to-top-fade">
        <div class="back-to-top"
             :style="`bottom:${this.bottom}; right:${this.right};`"
             v-show="fab"
             @click="backToTop">
            <slot>
                <button type="button" class="btn btn-rounded btn-to-top" v-scroll-to="{ el: `#${this.scrollTo}` }">
                    <span>{{ text }}</span>
                </button>
            </slot>
        </div>
    </transition>
</template>

<script>
    export default {
        name: 'FloatingButton',

        data() {
            return {
                fab: false,
            };
        },
        props: {
            right: {
                type: String,
                default: '30px',
            },
            bottom: {
                type: String,
                default: '30px',
            },
            text: {
                type: String,
                default: '',
            },
            scrollTo: {
                type: String,
                default: 'hero'
            }
        },
        mounted() {
            window.addEventListener('scroll', this.onScroll)
        },
        methods : {
            backToTop () {
                this.$emit('scrolled');
            },

            onScroll() {
                if (typeof window === 'undefined') {
                    return;
                }
                const top = window.pageYOffset || document.documentElement.offsetTop || 0;
                this.fab = top > 300;
            },
        },
    }
</script>