import Vue from 'vue'
import Typewriter from 'vue-typewriter';
import VueScrollTo from 'vue-scrollto';
import AOS from 'aos'
import VueGtag from 'vue-gtag';
import VueWebP from 'v-webp'

import './scss/app.scss';

import App from './App'

Vue.config.productionTip = false;

Vue.use(Typewriter);
Vue.use(VueScrollTo);
Vue.use(VueGtag, {
    config: { id: 'UA-137156900-1' }
});
Vue.use(VueWebP);

new Vue({
    created () {
        AOS.init({
            once: true,
            disable: 'phone',
            anchorPlacement: "top-center",
        });
        if(VueWebP.isSupportWebp) {
            document.querySelector('html').classList.add('web-p');
        }
    },
    render: h => h(App)
}).$mount('#app');