<template>
    <section id="projects">
        <div class="container">
            <div class="heading">
                <h1>{{ header }}</h1>
                <h2>{{ header_description }}</h2>
            </div>

            <div v-for="project in projects" class="showcase">
                <div class="col" :data-aos=project.image.animation>
                    <div class="image" :style="webP(project.image.url)"></div>
                </div>
                <div class="col">
                    <div :id=project.id class="showcase-heading" data-aos="fade-down" data-aos-delay="400">
                        <span>{{ project.header_description}}</span>
                        <h2>{{ project.header}}</h2>
                    </div>
                    <p data-aos="fade-left" :data-aos-anchor="'#'+project.id" data-aos-delay="700">
                        {{ project.description }}
                    </p>
                    <div class="list-icon" >
                        <template v-for="item in project.list">
                            <span data-aos="fade-left" :data-aos-anchor="'#'+project.id" :data-aos-delay=item.delay v-html=item.text></span>
                        </template>
                    </div>
                    <div class="link" data-aos="fade-up" :data-aos-anchor="'#'+project.id" :data-aos-delay=project.link.delay>
                        <hr>
                        <div>{{ project.link.desc }}</div>
                        <a :href=project.link.url target="_blank" rel="noopener">
                            <img :src=project.link.img :alt=project.link.alt>
                        </a>
                    </div>
                </div>
            </div>

        </div>
    </section>
</template>

<script>
    import VueWebP from 'v-webp';

    export default {
        name: 'Projects',
        data() {
            return {
                delay: 700,
            }
        },
        props: {
            header: String,
            header_description: String,
            projects: Array,
        },

        methods : {
            webP(url) {
                if (VueWebP.isSupportWebp) {
                    let regex = new RegExp(/([^\/]+)\.(jpg|png)\b/),
                        match = url.match(regex);
                    if (match) {
                        url = require(`../assets/${match[1]}.webp`);
                    }
                }
                return {
                    backgroundImage: 'url('+ url +')'
                }
            }
        }
    }
</script>